import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, AuthContextType, LoginResponse } from '../types/auth.types';
import apiService from '../services/api';

const AuthContext = createContext<AuthContextType | undefined>(undefined);

interface AuthProviderProps {
  children: ReactNode;
}

export function AuthProvider({ children }: AuthProviderProps) {
  const [user, setUser] = useState<User | null>(null);
  const [accessToken, setAccessToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Try to refresh token on app start
    const initializeAuth = async () => {
      try {
        await refreshToken();
      } catch {
        // Silent fail - user is not authenticated
      } finally {
        setIsLoading(false);
      }
    };

    initializeAuth();
  }, []);

  const login = async (email: string, password: string): Promise<void> => {
    try {
      const response = await apiService.axios.post<LoginResponse>('/api/auth/login', {
        email: email.trim(),
        password
      });

      const { user: userData, accessToken: token } = response.data;

      setUser(userData);
      setAccessToken(token);
      apiService.setAccessToken(token);
    } catch (error: any) {
      // Generic error message for security
      throw new Error('Invalid email or password');
    }
  };

  const logout = async (): Promise<void> => {
    try {
      await apiService.axios.post('/api/auth/logout');
    } catch {
      // Continue with logout even if server request fails
    } finally {
      setUser(null);
      setAccessToken(null);
      apiService.setAccessToken(null);
    }
  };

  const refreshToken = async (): Promise<void> => {
    try {
      const response = await apiService.axios.post('/api/auth/refresh');
      const { user: userData, accessToken: token } = response.data;

      setUser(userData);
      setAccessToken(token);
      apiService.setAccessToken(token);
    } catch (error) {
      // Clear auth state on refresh failure
      setUser(null);
      setAccessToken(null);
      apiService.setAccessToken(null);
      throw error;
    }
  };

  const value: AuthContextType = {
    user,
    accessToken,
    login,
    logout,
    refreshToken,
    isLoading
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth(): AuthContextType {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}
