import { NextApiRequest, NextApiResponse } from 'next';
import { createJobSchema } from '@/lib/validations/job';
import { prisma } from '@/lib/prisma';
import { Job } from '@/types/job';

interface ApiError {
  error: string;
  details?: string[];
}

export default async function handler(
  req: NextApiRequest,
  res: NextApiResponse<Job[] | Job | ApiError>
) {
  try {
    if (req.method === 'GET') {
      const jobs = await prisma.job.findMany({
        orderBy: { createdAt: 'desc' },
        select: {
          id: true,
          title: true,
          description: true,
          street: true,
          houseNumber: true,
          stair: true,
          postalCode: true,
          city: true,
          deliveryStreet: true,
          deliveryHouseNumber: true,
          deliveryStair: true,
          deliveryPostalCode: true,
          deliveryCity: true,
          createdAt: true,
          updatedAt: true,
        },
      });

      return res.status(200).json(
        jobs.map((job) => ({
          ...job,
          createdAt: job.createdAt.toISOString(),
          updatedAt: job.updatedAt.toISOString(),
        }))
      );
    }

    if (req.method === 'POST') {
      const validation = createJobSchema.safeParse(req.body);

      if (!validation.success) {
        return res.status(400).json({
          error: 'Validation failed',
          details: validation.error.errors.map(err => `${err.path.join('.')}: ${err.message}`),
        });
      }

      const {
        title,
        description,
        street,
        houseNumber,
        stair,
        postalCode,
        city,
        deliveryStreet,
        deliveryHouseNumber,
        deliveryStair,
        deliveryPostalCode,
        deliveryCity,
      } = validation.data;

      const job = await prisma.job.create({
        data: {
          title,
          description,
          street,
          houseNumber,
          stair: stair || null,
          postalCode,
          city,
          deliveryStreet: deliveryStreet || null,
          deliveryHouseNumber: deliveryHouseNumber || null,
          deliveryStair: deliveryStair || null,
          deliveryPostalCode: deliveryPostalCode || null,
          deliveryCity: deliveryCity || null,
        },
      });

      return res.status(201).json({
        ...job,
        createdAt: job.createdAt.toISOString(),
        updatedAt: job.updatedAt.toISOString(),
      });
    }

    return res.status(405).json({ error: 'Method not allowed' });
  } catch (error) {
    console.error('API Error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
}
