}) => {
  const [formData, setFormData] = useState({
    title: job?.title || '',
    description: job?.description || '',
    street: job?.street || '',
    houseNumber: job?.houseNumber || '',
    stair: job?.stair || '',
    postalCode: job?.postalCode || '',
    city: job?.city || '',
    deliveryStreet: job?.deliveryStreet || '',
    deliveryHouseNumber: job?.deliveryHouseNumber || '',
    deliveryStair: job?.deliveryStair || '',
    deliveryPostalCode: job?.deliveryPostalCode || '',
    deliveryCity: job?.deliveryCity || '',
  });

  const [showDeliveryAddress, setShowDeliveryAddress] = useState(
    Boolean(job?.deliveryStreet || job?.deliveryHouseNumber || job?.deliveryPostalCode || job?.deliveryCity)
  );

