import { Request, Response, NextFunction } from 'express';
import { z } from 'zod';

const base64PngRegex = /^data:image\/png;base64,([A-Za-z0-9+/]{4})*([A-Za-z0-9+/]{2}==|[A-Za-z0-9+/]{3}=)?$/;

const createCompletionReportSchema = z.object({
  body: z.object({
    workDescription: z.string().min(1, 'Work description is required').max(2000, 'Work description too long'),
    actualStart: z.string().datetime('Invalid actualStart date format'),
    actualEnd: z.string().datetime('Invalid actualEnd date format'),
    customerName: z.string().min(1, 'Customer name is required').max(100, 'Customer name too long'),
    customerSignature: z.string().min(1, 'Customer signature is required').regex(base64PngRegex, 'Invalid signature format')
  }).refine(data => {
    const start = new Date(data.actualStart);
    const end = new Date(data.actualEnd);
    return end > start;
  }, {
    message: 'actualEnd must be after actualStart',
    path: ['actualEnd']
  })
});

