      const utcResult = formatFinnishDateTime(utcTime);
      const helsinkiResult = formatFinnishDateTime(helsinkiTime);

      expect(utcResult).toBe(helsinkiResult);
    });
  });

  describe('formatFinnishDateTimeRange', () => {
    test('combines date when same day', () => {
