      const end = '2024-01-15T17:00:00Z';

      const result = formatFinnishDateTimeRange(start, end);
      expect(result).toMatch(/\d{2}\.\d{2}\.\d{4} \d{2}:\d{2}–\d{2}:\d{2}/);
    });

    test('shows full dates when different days', () => {
