      const start = '2024-01-15T09:00:00Z';
      const end = '2024-01-15T17:00:00Z';

      const hours = calculateHours(start, end);
      expect(hours).toBe(8);
    });

    test('handles fractional hours', () => {
      const start = '2024-01-15T09:00:00Z';
      const end = '2024-01-15T09:30:00Z';

      const hours = calculateHours(start, end);
      expect(hours).toBe(0.5);
    });

    test('returns zero for negative time difference', () => {
