import React, { useState, useEffect } from 'react';
import { Job, Driver } from '../types/job.types';
import { updateJob } from '../services/jobService';

interface EditJobModalProps {
  job: Job;
  drivers: Driver[];
  isOpen: boolean;
  onClose: () => void;
  onSuccess: (updatedJob: Job) => void;
}

interface FormData {
  title: string;
  description: string;
  scheduledStart: string;
  scheduledEnd: string;
  schedulingNote: string;
  assignedDriverId: string;
}

export const EditJobModal: React.FC<EditJobModalProps> = ({
  job,
  drivers,
  isOpen,
  onClose,
  onSuccess
}) => {
  const [formData, setFormData] = useState<FormData>({
    title: '',
    description: '',
    scheduledStart: '',
    scheduledEnd: '',
    schedulingNote: '',
    assignedDriverId: ''
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Pre-fill form when job changes
  useEffect(() => {
    if (job) {
      setFormData({
        title: job.title || '',
        description: job.description || '',
        scheduledStart: job.scheduledStart ? 
          new Date(job.scheduledStart).toISOString().slice(0, 16) : '',
        scheduledEnd: job.scheduledEnd ? 
          new Date(job.scheduledEnd).toISOString().slice(0, 16) : '',
        schedulingNote: job.schedulingNote || '',
        assignedDriverId: job.assignedDriverId || ''
      });
      setError(null);
    }
  }, [job]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      // Prepare payload with only changed fields and proper types
      const payload: Partial<Job> = {};

      if (formData.title !== job.title) payload.title = formData.title;
      if (formData.description !== job.description) payload.description = formData.description;
      if (formData.schedulingNote !== job.schedulingNote) payload.schedulingNote = formData.schedulingNote;
      if (formData.assignedDriverId !== job.assignedDriverId) {
        payload.assignedDriverId = formData.assignedDriverId || null;
      }

      // Handle datetime fields
      const scheduledStart = formData.scheduledStart ? 
        new Date(formData.scheduledStart).toISOString() : null;
      const scheduledEnd = formData.scheduledEnd ? 
        new Date(formData.scheduledEnd).toISOString() : null;

      if (scheduledStart !== job.scheduledStart) payload.scheduledStart = scheduledStart;
      if (scheduledEnd !== job.scheduledEnd) payload.scheduledEnd = scheduledEnd;

      // Only submit if there are changes
      if (Object.keys(payload).length === 0) {
        onClose();
        return;
      }

      const updatedJob = await updateJob(job.id, payload);
      onSuccess(updatedJob);
      onClose();

    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to update job';
      setError(errorMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2>Edit Job</h2>
          <button type="button" className="close-button" onClick={onClose}>×</button>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="title">Title *</label>
            <input
              type="text"
              id="title"
              name="title"
              value={formData.title}
              onChange={handleInputChange}
              required
              maxLength={200}
            />
          </div>

          <div className="form-group">
            <label htmlFor="description">Description</label>
            <textarea
              id="description"
              name="description"
              value={formData.description}
              onChange={handleInputChange}
              rows={4}
            />
          </div>

          <div className="form-group">
            <label htmlFor="scheduledStart">Scheduled Start</label>
            <input
              type="datetime-local"
              id="scheduledStart"
              name="scheduledStart"
              value={formData.scheduledStart}
              onChange={handleInputChange}
            />
          </div>

          <div className="form-group">
            <label htmlFor="scheduledEnd">Scheduled End</label>
            <input
              type="datetime-local"
              id="scheduledEnd"
              name="scheduledEnd"
              value={formData.scheduledEnd}
              onChange={handleInputChange}
            />
          </div>

          <div className="form-group">
            <label htmlFor="schedulingNote">Scheduling Note</label>
            <input
              type="text"
              id="schedulingNote"
              name="schedulingNote"
              value={formData.schedulingNote}
              onChange={handleInputChange}
              placeholder="Time to be agreed with customer"
            />
          </div>

          <div className="form-group">
            <label htmlFor="assignedDriverId">Assigned Driver</label>
            <select
              id="assignedDriverId"
              name="assignedDriverId"
              value={formData.assignedDriverId}
              onChange={handleInputChange}
            >
              <option value="">Select driver...</option>
              {drivers.filter(driver => driver.status === 'active').map(driver => (
                <option key={driver.id} value={driver.id}>
                  {driver.name}
                </option>
              ))}
            </select>
          </div>

          {error && (
            <div className="error-message" role="alert">
              {error}
            </div>
          )}

          <div className="modal-actions">
            <button type="button" onClick={onClose} disabled={isSubmitting}>
              Cancel
            </button>
            <button type="submit" disabled={isSubmitting}>
              {isSubmitting ? 'Saving...' : 'Save Changes'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};
