                <td>{job.assignedDriver?.name || 'Unassigned'}</td>
                <td>{job.status}</td>
                {canEdit && (
                  <td>
                    <button
                      type="button"
                      className="edit-button"
                      onClick={() => handleEditClick(job)}
                      aria-label={`Edit job ${job.title}`}
                    >
                      Edit
                    </button>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {editingJob && (
        <EditJobModal
          job={editingJob}
          drivers={drivers}
          isOpen={isEditModalOpen}
          onClose={handleCloseEditModal}
          onSuccess={handleEditSuccess}
        />
      )}
    </div>
  );
};
