import { Request, Response, NextFunction } from 'express';
import { z } from 'zod';

const updateJobNotesSchema = z.object({
  body: z.object({
    driverNotes: z.string().max(1000, 'Driver notes cannot exceed 1000 characters').trim()
  })
});

export const validateUpdateJobNotes = (req: Request, res: Response, next: NextFunction): void => {
  try {
    updateJobNotesSchema.parse(req);
    next();
  } catch (error) {
    if (error instanceof z.ZodError) {
      res.status(400).json({
        error: 'Validation failed',
        details: error.errors.map(e => e.message)
      });
      return;
    }
    res.status(400).json({ error: 'Invalid request' });
  }
};
