import { Job } from '../types/job';
import { User } from '../types/user';

const API_BASE = process.env.REACT_APP_API_BASE_URL || '/api';

interface ApiResponse<T> {
  success: boolean;
  data: T;
  message?: string;
}

interface ApiError {
  success: false;
  message: string;
  code?: string;
}

class ApiService {
  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<T> {
    const url = `${API_BASE}${endpoint}`;

    const config: RequestInit = {
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
      ...options,
    };

    try {
      const response = await fetch(url, config);

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const result: ApiResponse<T> | ApiError = await response.json();

      if (!result.success) {
        throw new Error(result.message || 'API request failed');
      }

      return (result as ApiResponse<T>).data;
    } catch (error) {
      console.error(`API request failed for ${endpoint}:`, error);
      throw error;
    }
  }

  async getJobs(): Promise<Job[]> {
    return this.request<Job[]>('/jobs?status=DRAFT&status=ASSIGNED');
  }

  async getDrivers(): Promise<User[]> {
    return this.request<User[]>('/users?role=DRIVER');
  }

  async updateJobAssignment(
    jobId: string,
    assignedDriverId: string | null
  ): Promise<Job> {
    return this.request<Job>(`/jobs/${jobId}`, {
      method: 'PATCH',
      body: JSON.stringify({ assignedDriverId }),
    });
  }
}

export const apiService = new ApiService();
