import { Request, Response } from 'express';
import { Job } from '../models/Job';
import { AppError } from '../utils/AppError';

interface UpdateJobRequest extends Request {
  params: { id: string };
  body: {
    title?: string;
    description?: string;
    assignedDriverId?: string;
    scheduledStart?: string;
    scheduledEnd?: string;
    schedulingNote?: string;
    pickupAddress?: {
      street: string;
      city: string;
      state: string;
      zipCode: string;
    };
    deliveryAddress?: {
      street: string;
      city: string;
      state: string;
      zipCode: string;
    };
  };
}

export const jobController = {
  // Existing methods...

  updateJob: async (req: UpdateJobRequest, res: Response): Promise<void> => {
    try {
      const { id } = req.params;
      const updates = req.body;

      // Check if job exists
      const existingJob = await Job.findById(id);
      if (!existingJob) {
        throw new AppError('Job not found', 404);
      }

      // Validate scheduled dates if both are provided
      if (updates.scheduledStart && updates.scheduledEnd) {
        const startDate = new Date(updates.scheduledStart);
        const endDate = new Date(updates.scheduledEnd);

        if (startDate >= endDate) {
          throw new AppError('Scheduled start must be before scheduled end', 400);
        }
      }

      // Update only provided fields
      const updatedJob = await Job.findByIdAndUpdate(
        id,
        { 
          ...updates,
          updatedAt: new Date()
        },
        { 
          new: true, 
          runValidators: true 
        }
      ).populate('assignedDriverId', 'name email');

      res.status(200).json({
        success: true,
        data: updatedJob
      });
    } catch (error) {
      if (error instanceof AppError) {
        res.status(error.statusCode).json({
          success: false,
          message: error.message
        });
      } else {
        res.status(500).json({
          success: false,
          message: 'Internal server error'
        });
      }
    }
  }
};
