    goToWeek 
  } = useWeekNavigation();

  if (error) {
    return (
      <div className="weekly-view-error" role="alert">
        <h3>Virhe ladattaessa tehtäviä</h3>
        <p>{error}</p>
      </div>
    );
  }

  return (
    <div className="weekly-view">
      <WeekNavigation
        currentWeek={currentWeek}
        onWeekChange={goToWeek}
        onPrevWeek={goToPrevWeek}
        onNextWeek={goToNextWeek}
      />

      <UnscheduledPool 
        jobs={jobs} 
        onJobClick={onJobClick}
      />

      {loading ? (
        <div className="loading-spinner" aria-label="Ladataan tehtäviä...">
          Ladataan...
        </div>
      ) : (
        <div className="week-grid">
          {weekDays.map(day => (
            <DayColumn
              key={day.toISOString()}
              date={day}
              jobs={jobs}
              onJobClick={onJobClick}
            />
          ))}
        </div>
      )}
    </div>
  );
};
