import { formatFinnishDateTime, formatFinnishDate, formatISODate, formatTimeRange } from '../../src/utils/dateFormatters';

describe('dateFormatters', () => {
  const testDate = new Date('2024-01-15T14:30:00Z');
  const testDateString = '2024-01-15T14:30:00Z';

  describe('formatFinnishDateTime', () => {
    it('should format date object correctly', () => {
      const result = formatFinnishDateTime(testDate);
      expect(result).toBe('15.01.2024 14:30');
    });

    it('should format date string correctly', () => {
      const result = formatFinnishDateTime(testDateString);
      expect(result).toBe('15.01.2024 14:30');
    });

    it('should return empty string for null', () => {
      const result = formatFinnishDateTime(null);
      expect(result).toBe('');
    });

    it('should handle invalid date string', () => {
      expect(() => formatFinnishDateTime('invalid-date')).toThrow();
    });
  });

  describe('formatTimeRange', () => {
    const startDate = new Date('2024-01-15T14:30:00Z');
    const endDate = new Date('2024-01-15T16:45:00Z');

    it('should format complete time range', () => {
      const result = formatTimeRange(startDate, endDate);
      expect(result).toBe('15.01.2024 14:30–16:45');
    });

    it('should handle only start date', () => {
      const result = formatTimeRange(startDate, null);
      expect(result).toBe('15.01.2024 14:30');
    });

    it('should handle only end date', () => {
      const result = formatTimeRange(null, endDate);
      expect(result).toBe('– 15.01.2024 16:45');
    });

    it('should return empty string for both null', () => {
      const result = formatTimeRange(null, null);
      expect(result).toBe('');
    });
  });
});
