      expect(mockResponse.json).toHaveBeenCalledWith({
        jobs: mockJobs,
        date: '2024-01-15',
        total: 1,
      });
    });

    it('should return 401 for unauthenticated request', async () => {
      mockRequest.user = undefined;
      mockRequest.query = { date: '2024-01-15' };

