    await cleanupTestDatabase();
  });

  describe('GET /api/driver/my-jobs', () => {
    it('should return jobs for authenticated driver', async () => {
      const authToken = await getDriverAuthToken('driver1');

      const response = await request(app)
        .get('/api/driver/my-jobs')
        .query({ date: '2024-01-15' })
        .set('Authorization', `Bearer ${authToken}`)
        .expect(200);

      expect(response.body).toMatchObject({
        jobs: expect.any(Array),
        date: '2024-01-15',
        total: expect.any(Number),
      });
    });

    it('should return 401 without authentication', async () => {
      await request(app)
        .get('/api/driver/my-jobs')
        .query({ date: '2024-01-15' })
        .expect(401);
    });

    it('should filter jobs by driver and date', async () => {
      const driver1Token = await getDriverAuthToken('driver1');
      const driver2Token = await getDriverAuthToken('driver2');

      // Create jobs for both drivers
      await createTestJob('driver1', '2024-01-15T10:00:00Z');
      await createTestJob('driver2', '2024-01-15T10:00:00Z');
      await createTestJob('driver1', '2024-01-16T10:00:00Z');

      const response = await request(app)
        .get('/api/driver/my-jobs')
        .query({ date: '2024-01-15' })
        .set('Authorization', `Bearer ${driver1Token}`)
        .expect(200);

      expect(response.body.jobs).toHaveLength(1);
      expect(response.body.jobs[0].assignedDriverId).toBe('driver1');
    });

    it('should enforce rate limiting', async () => {
      const authToken = await getDriverAuthToken('driver1');

      // Make 31 requests (exceeding limit of 30)
      const promises = Array(31).fill(0).map(() =>
        request(app)
          .get('/api/driver/my-jobs')
          .query({ date: '2024-01-15' })
          .set('Authorization', `Bearer ${authToken}`)
      );

      const responses = await Promise.all(promises);
      const rateLimitedResponses = responses.filter(r => r.status === 429);

      expect(rateLimitedResponses.length).toBeGreaterThan(0);
    });
  });
});
